mapper.select:
SELECT r.report_id, r.student_id, r.student_name, u.student_no, r.major_name, r.class_name, r.topic_id, r.topic_title AS topic_name, r.advisor_names, r.report_date, r.arrangement_id, r.research_status, r.purpose_significance, r.research_content, r.innovation_points, r.problems_to_solve, r.progress_expectation, r.current_conditions, r.advisor_opinion, r.college_opinion, r.submit_time, r.status, r.create_time, r.update_time FROM opening_report r LEFT JOIN user_info u ON r.student_id = u.user_id WHERE r.is_deleted = 0
AND u.enterprise_id = #{enterpriseId}
AND r.student_name LIKE CONCAT('%', #{studentName}, '%')
AND r.status = #{status}
AND r.arrangement_id = #{arrangementId}
ORDER BY r.create_time DESC
